@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div class="@RootCssClass" @attributes="AdditionalAttributes">
    @* Primary action half *@
    <Button Variant="Variant"
            Size="Size"
            Disabled="Disabled"
            OnClick="OnClick"
            Class="@PrimaryButtonClass">
        @if (ChildContent != null)
        {
            @ChildContent
        }
        else
        {
            @Text
        }
    </Button>

    @* Chevron / dropdown half *@
    <DropdownMenu @bind-Open="_open">
        @* AsChild folds the trigger's menu ARIA (data-state/aria-haspopup/aria-expanded/
           aria-controls) + toggle onclick onto this single focusable <button>, instead of
           leaving them on a separate non-focusable role=button wrapper a screen reader
           never lands on (triage #121). aria-haspopup is dropped here because the slot
           already supplies it. *@
        <DropdownMenuTrigger AsChild Disabled="Disabled">
            <Button Variant="Variant"
                    Size="Size"
                    Disabled="Disabled"
                    Class="@ChevronButtonClass"
                    aria-label="@L["Common.MoreOptions"]">
                <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" Class="h-4 w-4 shrink-0 transition-transform duration-200 group-data-[state=open]:rotate-180" />
            </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent>
            @MenuContent
        </DropdownMenuContent>
    </DropdownMenu>
</div>

@code {
    [Parameter] public string? Text { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public RenderFragment? MenuContent { get; set; }
    [Parameter] public EventCallback<Microsoft.AspNetCore.Components.Web.MouseEventArgs> OnClick { get; set; }
    [Parameter] public Button.ButtonVariant Variant { get; set; } = Button.ButtonVariant.Default;
    [Parameter] public Button.ButtonSize Size { get; set; } = Button.ButtonSize.Default;
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _open;

    // Size-aware icon-only width for the chevron half
    private string ChevronWidth => Size switch
    {
        Button.ButtonSize.Sm => "w-7",
        Button.ButtonSize.Lg => "w-10",
        _ => "w-9"
    };

    private string RootCssClass => Cx.Merge(
        "inline-flex",
        Class);

    // Primary button: square right edge, collapsed right border
    private const string PrimaryButtonClass = "rounded-e-none border-e-0";

    // Chevron button: square left edge, collapsed left border (via -ms-px)
    private string ChevronButtonClass => Cx.Join(
        "rounded-s-none -ms-px px-0 shrink-0",
        ChevronWidth);
}
